def convert_custom_object_to_dict(obj: Any) -> dict:
    """Convert a custom object to a serializable dictionary.

    This is a helper for users who need to store custom objects.
    The object's __dict__ is extracted and validated.

    Args:
        obj: Any object with a __dict__ attribute.

    Returns:
        dict with '_type' key indicating original class name and all attributes.
    """
    if not hasattr(obj, '__dict__'):
        raise TypeError(f"Object of type {type(obj).__name__} has no __dict__")

    result = {'_type': type(obj).__name__}
    prefs = UserPreferences.__new__(UserPreferences)
    for key, value in obj.__dict__.items():
        if isinstance(key, str) and not key.startswith('_'):
            try:
                prefs._validate_value(value, key)
                result[key] = value
            except TypeError:
                # Try converting nested custom objects
                if hasattr(value, '__dict__'):
                    result[key] = convert_custom_object_to_dict(value)
                else:
                    raise
    return result


def reconstruct_custom_object(data: dict, class_registry: dict) -> Any:
    """Reconstruct a custom object from a dictionary with '_type' key.

    Args:
        data: Dictionary with '_type' key and attribute data.
        class_registry: Mapping of type name strings to classes.

    Returns:
        Reconstructed object or original dict if type not in registry.
    """
    if not isinstance(data, dict) or '_type' not in data:
        return data

    type_name = data['_type']
    if type_name not in class_registry:
        return data

    cls = class_registry[type_name]
    obj = cls.__new__(cls)
    for key, value in data.items():
        if key == '_type':
            continue
        if isinstance(value, dict) and '_type' in value:
            value = reconstruct_custom_object(value, class_registry)
        setattr(obj, key, value)
    return obj


